def gen(rng, size):
    m = rng.randint(1, max(1, min(40, size)))
    n = rng.randint(1, max(1, min(40, size)))
    g = [['.'] * n for _ in range(m)]
    def free(r, c):
        for dr in (-1, 0, 1):
            for dc in (-1, 0, 1):
                nr, nc = r + dr, c + dc
                if 0 <= nr < m and 0 <= nc < n and g[nr][nc] == 'X':
                    return False
        return True
    attempts = m * n
    for _ in range(attempts):
        r = rng.randrange(m)
        c = rng.randrange(n)
        horiz = rng.random() < 0.5
        length = rng.randint(1, 4)
        cells = []
        ok = True
        for i in range(length):
            rr = r + (0 if horiz else i)
            cc = c + (i if horiz else 0)
            if not (0 <= rr < m and 0 <= cc < n) or not free(rr, cc):
                ok = False
                break
            cells.append((rr, cc))
        if ok:
            for rr, cc in cells:
                g[rr][cc] = 'X'
    return [[list(row) for row in g]]

