class Solution:
    def countBattleships(self, board):
        m = len(board)
        n = len(board[0])
        seen = [[False] * n for _ in range(m)]
        count = 0
        for r in range(m):
            for c in range(n):
                if board[r][c] == 'X' and not seen[r][c]:
                    count += 1
                    stack = [(r, c)]
                    seen[r][c] = True
                    while stack:
                        cr, cc = stack.pop()
                        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nr, nc = cr + dr, cc + dc
                            if 0 <= nr < m and 0 <= nc < n and board[nr][nc] == 'X' and not seen[nr][nc]:
                                seen[nr][nc] = True
                                stack.append((nr, nc))
        return count

