var countBattleships = function(board) {
    const m = board.length, n = board[0].length;
    let count = 0;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            if (board[r][c] !== 'X') continue;
            if (r > 0 && board[r - 1][c] === 'X') continue;
            if (c > 0 && board[r][c - 1] === 'X') continue;
            count++;
        }
    }
    return count;
};
